-- Contractor brief schema v3: company story + web content section

do $$
declare
  contractor_schema jsonb := '{"sections":[{"id":"confirm_data","title":"Confirma tus datos","description":"Revisa la información que ya tenemos y complétala solo si falta algo.","fields":[{"key":"contact_name","type":"text","label":"Nombre de contacto","required":true},{"key":"contact_email","type":"email","label":"Email de contacto","required":true},{"key":"contact_phone","type":"phone","label":"Teléfono de contacto","required":true},{"key":"company_name","type":"text","label":"Nombre de la empresa","required":true},{"key":"use_same_contact_for_business","type":"checkbox","label":"Usar el mismo email y teléfono del contacto para el negocio","required":false},{"key":"business_email","type":"email","label":"Email del negocio","required":false,"visible_when":{"operator":"and","conditions":[{"field":"use_same_contact_for_business","op":"is_empty"}]}},{"key":"business_phone","type":"phone","label":"Teléfono del negocio","required":false,"visible_when":{"operator":"and","conditions":[{"field":"use_same_contact_for_business","op":"is_empty"}]}},{"key":"full_address","type":"textarea","label":"Dirección completa del negocio","required":true},{"key":"existing_website","type":"text","label":"Sitio web actual (si tiene uno)","required":false,"placeholder":"www.tuempresa.com"},{"key":"social_links","type":"dynamic_list","label":"Redes sociales","required":false,"help_text":"Opcional. Usa el botón para añadir cada red (Facebook, Instagram, etc.).","min_items":0,"add_button_label":"Añadir red social","item_label_template":"Red social {index}","item_placeholder":"Ej: Facebook|facebook.com/tuempresa"}]},{"id":"about_business","title":"Sobre tu negocio","fields":[{"key":"company_founded_year","type":"number","label":"Año de fundación de la empresa","required":false,"min":1900,"max":2026},{"key":"years_experience","type":"number","label":"Años de experiencia (calculado)","required":false,"help_text":"Se calcula automáticamente a partir del año de fundación."},{"key":"has_insurance","type":"radio","label":"¿Tienes seguro?","required":false,"options":["Sí","No"]},{"key":"license_number","type":"text","label":"Número de licencia","required":false,"visible_when":{"operator":"and","conditions":[{"field":"has_insurance","op":"equals","value":"Sí"}]}},{"key":"service_areas","type":"textarea","label":"Áreas / ciudades donde trabajas","required":false},{"key":"business_hours","type":"textarea","label":"Horario de atención","required":false}]},{"id":"web_content","title":"Historia y contenido para tu web","description":"Esta información nos ayuda a escribir las páginas Sobre nosotros, inicio y secciones de confianza.","fields":[{"key":"company_story","type":"textarea","label":"Historia de la empresa","required":false,"help_text":"Cuéntanos cómo empezó el negocio, quién lo fundó, hitos importantes y qué los hace únicos hoy.","placeholder":"Ej: Empezamos en 2010 como un equipo familiar de 2 personas y hoy atendemos todo el condado…"},{"key":"company_tagline","type":"text","label":"Eslogan o frase principal","required":false,"placeholder":"Ej: \"Calidad en cada proyecto\" o \"Tu hogar, nuestra prioridad\""},{"key":"why_choose_us","type":"textarea","label":"¿Por qué deberían elegirte?","required":false,"help_text":"3–5 razones claras para un visitante nuevo (experiencia, garantía, rapidez, etc.)."},{"key":"certifications_awards","type":"textarea","label":"Certificaciones, premios o membresías","required":false,"placeholder":"Ej: Licencia #12345, BBB A+, miembro de NARI, premio Best of 2024…"},{"key":"warranties_guarantees","type":"textarea","label":"Garantías que ofreces","required":false,"placeholder":"Ej: Garantía de 10 años en materiales, 2 años en mano de obra…"},{"key":"customer_testimonials","type":"textarea","label":"Testimonios o reseñas de clientes","required":false,"help_text":"Pega aquí frases de clientes satisfechos o indica si las subirás después. Opcional."},{"key":"emergency_services","type":"radio","label":"¿Ofreces servicio de emergencia o fuera de horario?","required":false,"options":["Sí, 24/7","Sí, solo emergencias","No"]}]},{"id":"services","title":"Tus servicios","fields":[{"key":"services_offered","type":"multi_select","label":"Servicios ofrecidos","required":false,"options":["Roof Repairs","Roof Replacements","Chimney Repairs","Siding Repairs","Siding Replacements","Vinyl Siding Installation","Deck Repairs","Deck Replacements","New Deck Construction","Composite Decking (Trex)","Railing Systems","Gutter Cleaning","Gutter Repairs","Gutter Replacements","Gutter Installation","Exterior Painting","Interior Painting","Power Washing","Exterior Renovations","General Home Improvements","Otros"]},{"key":"other_services","type":"text","label":"Otros servicios","required":false,"visible_when":{"operator":"and","conditions":[{"field":"services_offered","op":"contains","value":"Otros"}]}},{"key":"primary_service","type":"text","label":"Servicio principal / más rentable","required":false,"help_text":"Elige uno de los servicios que marcaste arriba."},{"key":"free_offers","type":"multi_select","label":"¿Ofreces inspecciones o estimados gratis?","required":false,"options":["Inspección gratis","Estimado gratis","Ambos","Ninguno"]},{"key":"insurance_claims","type":"radio","label":"¿Trabajas con seguros / claims?","required":false,"options":["Sí","No"]},{"key":"accepts_xactimate","type":"radio","label":"¿Aceptas Xactimate?","required":false,"options":["Sí","No"],"visible_when":{"operator":"and","conditions":[{"field":"insurance_claims","op":"equals","value":"Sí"}]}},{"key":"differentiators","type":"textarea","label":"Qué te hace diferente de la competencia","required":false,"help_text":"Sugerimos 3–5 razones."}]},{"id":"contact_preferences","title":"Cómo quieres que te contacten","fields":[{"key":"preferred_contact_methods","type":"multi_select","label":"Mejor forma de contacto","required":false,"options":["Llamada telefónica","SMS / texto","WhatsApp","Formulario web","Email"]},{"key":"form_notification_email","type":"email","label":"Email para recibir formularios del sitio","required":false},{"key":"whatsapp_business","type":"phone","label":"Número de WhatsApp Business","required":false}]},{"id":"visual_content","title":"Contenido visual","fields":[{"key":"logo_file","type":"file","label":"Logo","required":false,"accept":".jpg,.jpeg,.png,.webp,.svg"},{"key":"has_project_photos","type":"radio","label":"¿Tienes fotos de proyectos terminados?","required":false,"options":["Sí, las subiré ahora","No tengo, usen fotos profesionales (stock)"]},{"key":"before_after_photos","type":"radio","label":"¿Tienes fotos antes y después?","required":false,"options":["Sí","No"]},{"key":"has_team_photos","type":"radio","label":"¿Tienes fotos del equipo / camiones / uniformes?","required":false,"options":["Sí","No"]}]},{"id":"language_audience","title":"Idioma y audiencia del sitio","fields":[{"key":"site_language","type":"radio","label":"Idioma del sitio web","required":false,"options":["Inglés","Español","Bilingüe (ambos)"]},{"key":"target_customers","type":"multi_select","label":"Cliente típico","required":false,"options":["Homeowners","Property managers","Comercial","Otro"]},{"key":"target_customers_other","type":"text","label":"Otro tipo de cliente","required":false,"visible_when":{"operator":"and","conditions":[{"field":"target_customers","op":"contains","value":"Otro"}]}}]},{"id":"brand_style","title":"Marca y estilo","fields":[{"key":"brand_colors_option","type":"radio","label":"¿Tienes colores de marca específicos?","required":false,"options":["Sí","No, usen los del logo"]},{"key":"brand_color_1","type":"text","label":"Color principal","required":false,"visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Sí"}]}},{"key":"brand_color_2","type":"text","label":"Color secundario","required":false,"visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Sí"}]}},{"key":"brand_color_3","type":"text","label":"Color de acento","required":false,"visible_when":{"operator":"and","conditions":[{"field":"brand_colors_option","op":"equals","value":"Sí"}]}},{"key":"reference_sites","type":"dynamic_list","label":"Sitios web de referencia","required":false,"min_items":0,"add_button_label":"Añadir sitio de referencia","item_placeholder":"www.ejemplo.com"},{"key":"site_exclusions","type":"textarea","label":"¿Hay algo que NO quieres en tu sitio?","required":false}]},{"id":"extras","title":"Extras","fields":[{"key":"wants_blog","type":"radio","label":"¿Quieres blog en tu sitio?","required":false,"options":["Sí","No"]},{"key":"client_notes","type":"textarea","label":"Notas adicionales","required":false},{"key":"brief_confirmation","type":"checkbox","label":"Confirmo que la información proporcionada es precisa y autorizo su uso para el desarrollo de mi sitio web.","required":true}]}]}'::jsonb;
begin
  update public.form_templates
  set schema = contractor_schema,
      updated_at = now()
  where is_system = true
    and slug = 'project_brief';

  update public.form_instances fi
  set schema = contractor_schema,
      updated_at = now()
  where fi.slug = 'project_brief';
end $$;
